/**
 * PaygState
 *
 * Pay-as-you-go (overage) accounting for the current period.
 *
 * Populated when ``credit_balance`` is negative. Tenants without a payment method see the same negative balance but cannot be charged until a card is added.
 */
export type PaygState = {
    /**
     * Last Charge At
     *
     * Timestamp of the most recent successful PAYG charge.
     */
    last_charge_at?: string | null;
    /**
     * Pending Overage Credits
     *
     * Absolute value of the negative balance, in credits. Always >= 0; the sign is implied (overage).
     */
    pending_overage_credits: string;
    /**
     * Pending Overage Usd
     *
     * Pending overage in USD at the current PAYG rate (``PAYG_OVERAGE_RATE_USD_PER_MINUTE`` = $0.065/credit today).
     */
    pending_overage_usd: string;
    /**
     * Threshold Credits
     *
     * Credit threshold above which the next pay-as-you-go charge fires.
     */
    threshold_credits: string;
};

