/**
 * SelectPlanResponse
 *
 * ``POST /billing/plans/{slug}/select`` payload.
 *
 * Returns the new state after the Stripe subscription is created, updated, or scheduled for cancellation. ``status`` is one of:
 *
 * * A Stripe subscription status (``active``, ``trialing``, ``incomplete``, ``past_due``, …).
 * * ``free`` — an already-free tenant re-affirmed the free tier; no Stripe call was needed.
 * * ``scheduled_cancellation`` — a downgrade from a paid tier to free; the subscription stays active through the paid period.
 *
 * When ``status`` is ``incomplete`` (first charge declined), the response includes ``payment_intent_client_secret`` so the client can confirm the payment. The plan only advances to the new tier after Stripe transitions the subscription to ``active``.
 */
export type SelectPlanResponse = {
    /**
     * Awaiting Payment
     *
     * True when a paid-to-paid upgrade is pending payment of the proration invoice. ``status`` still reads ``active`` (the subscription is active on the old price); confirm the PaymentIntent to apply the upgrade.
     */
    awaiting_payment?: boolean;
    /**
     * Payment Intent Client Secret
     *
     * Stripe PaymentIntent client secret for the first invoice. Present when ``status`` is ``incomplete``; pass it to the client to confirm the existing payment (do not create a new subscription on retry, which would double-charge).
     */
    payment_intent_client_secret?: string | null;
    /**
     * Plan Slug
     */
    plan_slug: string;
    /**
     * Status
     */
    status: string;
    /**
     * Subscription Id
     */
    subscription_id?: string | null;
};

